import { safeLogMessage } from './redaction';

export type LogFn = (message: string) => void;

export interface SafeLogger {
  info: LogFn;
  warning: LogFn;
  error: LogFn;
  debug: LogFn;
}

export function createSafeLogger(apiKey?: string, impl?: Partial<SafeLogger>): SafeLogger {
  const sanitize = (msg: string) => safeLogMessage(msg, apiKey);
  return {
    info: (msg) => (impl?.info ?? console.log.bind(console))(sanitize(msg)),
    warning: (msg) => (impl?.warning ?? console.warn.bind(console))(sanitize(msg)),
    error: (msg) => (impl?.error ?? console.error.bind(console))(sanitize(msg)),
    debug: (msg) => (impl?.debug ?? (() => {}))(sanitize(msg)),
  };
}
